// src/styles/infinitePopovers.scss
var infinitePopovers_default = '@charset "UTF-8";\n.popover {\n  z-index: 999;\n  position: fixed;\n  padding: 0;\n  left: 0;\n  top: 0;\n  will-change: transform;\n  display: flex;\n  flex-direction: column;\n  width: min(40vw, 40vh);\n  height: min(40vw, 40vh);\n  border-radius: 5px;\n  box-shadow: 0 0 8px 0 rgba(0, 0, 0, 0.3);\n  overflow: hidden;\n}\n\n/* \u5DE5\u5177\u680F\uFF1A\u5B9E\u8272 */\n.popover > .popover-toolbar {\n  display: flex;\n  align-items: center;\n  gap: 0.25rem;\n  padding: 0.25rem 0.5rem;\n  background-color: var(--light);\n  border-bottom: 1px solid var(--lightgray);\n  cursor: grab;\n  user-select: none;\n  flex: 0 0 20px;\n  z-index: 1;\n}\n\n.popover.pinned > .popover-toolbar {\n  background-color: var(--lightgray);\n  border-bottom-color: var(--gray);\n}\n\n.popover > .popover-toolbar:active {\n  cursor: grabbing;\n}\n\n.popover > .popover-toolbar button {\n  background: none;\n  border: none;\n  cursor: pointer;\n  padding: 0 0.25rem;\n  color: var(--dark);\n  display: flex;\n  align-items: center;\n}\n\n.popover > .popover-toolbar button svg {\n  width: 14px;\n  height: 14px;\n}\n\n.popover > .popover-toolbar .toolbar-spacer {\n  flex: 1;\n}\n\n/* \u5185\u5BB9\u533A\u5BB9\u5668 */\n.popover > .popover-inner {\n  flex: 1;\n  min-height: 0;\n  display: flex;\n  flex-direction: column;\n  background-color: var(--light);\n}\n\n/* \u6EDA\u52A8\u5185\u5BB9 */\n.popover > .popover-inner > .popover-content {\n  flex: 1;\n  min-height: 0;\n  overflow-y: auto;\n  padding: 1rem 1rem 1rem 1rem;\n  border-right: 10px solid transparent;\n  overscroll-behavior: contain;\n  box-sizing: border-box;\n  opacity: 0.6;\n}\n\n.active-popover > .popover-inner > .popover-content,\n.popover.pinned > .popover-inner > .popover-content {\n  opacity: 1;\n}\n\n.popover > .popover-inner > .popover-content[data-content-type*=pdf],\n.popover > .popover-inner > .popover-content[data-content-type*=image] {\n  padding: 0;\n}\n\n.popover > .popover-inner > .popover-content[data-content-type*=image] img {\n  margin: 0;\n  border-radius: 0;\n  display: block;\n}\n\n.popover > .popover-inner > .popover-content[data-content-type*=pdf] iframe {\n  width: 100%;\n}\n\n.popover h1 {\n  font-size: 1.5rem;\n}\n\n@media all and (max-width: 700px) {\n  .popover {\n    display: none !important;\n  }\n}\n@media (prefers-color-scheme: dark) {\n  .popover {\n    box-shadow: 0 0 8px 0 rgba(0, 0, 0, 0.5);\n  }\n  .popover > .popover-toolbar button {\n    color: var(--dark);\n  }\n}';

